  selectedCategory: string | null,
): Integration[] {
  const query = searchQuery.toLowerCase();

  return integrations.filter((integration) => {
    const guide = OAUTH_SETUP_GUIDES[integration.id];

    const matchesSearch =
      query === "" ||
      integration.name.toLowerCase().includes(query) ||
      integration.id.toLowerCase().includes(query);

    const matchesCategory = selectedCategory === null || guide?.category === selectedCategory;

    return matchesSearch && matchesCategory;
  });
}

export function groupIntegrationsByCategory(
  integrations: Integration[],
): Record<string, Integration[]> {
  const groups: Record<string, Integration[]> = {};

  for (const integration of integrations) {
    const category = OAUTH_SETUP_GUIDES[integration.id]?.category ?? "other";
    (groups[category] ??= []).push(integration);
  }

  return groups;
}

export function buildSetupSteps(
  envChecked: boolean,
  allConnected: boolean,
  markEnvChecked: () => void,
): SetupStep[] {
  return [
    {
      id: "env",
      title: "Configure Environment Variables",
      description: "Add your OAuth credentials to the .env file",
      completed: envChecked,
      action: markEnvChecked,
    },
    {
      id: "oauth",
      title: "Create OAuth Apps",
      description: "Set up OAuth applications for each service",
      completed: false,
    },
    {
      id: "connect",
      title: "Connect Services",
      description: "Authorize your app to access each service",
      completed: allConnected,
    },
  ];
}

export function getTokenStorageStyles(
  tokenStorage: TokenStorageStatus | null,
): TokenStorageStyles | null {
  if (!tokenStorage) return null;

  const isMemory = tokenStorage.mode === "memory";

  return {
    container: `rounded-2xl p-6 shadow-sm border mb-8 ${
      isMemory
        ? "bg-amber-50 dark:bg-amber-900/20 border-amber-200 dark:border-amber-800"
        : "bg-green-50 dark:bg-green-900/20 border-green-200 dark:border-green-800"
    }`,
    iconWrapper: `w-10 h-10 rounded-full flex items-center justify-center ${
      isMemory ? "bg-amber-100 dark:bg-amber-900" : "bg-green-100 dark:bg-green-900"
    }`,
    title: `font-semibold ${
      isMemory ? "text-amber-800 dark:text-amber-200" : "text-green-800 dark:text-green-200"
    }`,
    text: `text-sm mt-1 ${
      isMemory ? "text-amber-700 dark:text-amber-300" : "text-green-700 dark:text-green-300"
    }`,
    isMemory,
  };
}

