import { tool } from "veryfront/tool";
import { defineSchema } from "veryfront/schemas";
import { formatAsStorage, getPage, updatePage } from "../../lib/confluence-client.ts";

function toStorageContent(content?: string): string | undefined {
  if (!content || !content.trim()) return undefined;

  const trimmed = content.trim();
  if (trimmed.startsWith("<")) return content;

  return formatAsStorage(content);
}

function nonEmpty(value: string | undefined): string | undefined {
  return value && value.trim() ? value : undefined;
}

export default tool({
  id: "update-page",
  description:
    "Update the content or title of an existing Confluence page. Requires the current version number.",
  inputSchema: defineSchema((v) => v.object({
    pageId: v.string().describe("The ID of the page to update"),
    title: v
      .string()
      .optional()
      .describe("New title for the page (leave empty to keep current title)"),
    content: v
      .string()
      .optional()
      .describe("New content for the page (can be plain text or Confluence storage format HTML)"),
    versionMessage: v
      .string()
      .optional()
      .describe("Optional message describing the changes made"),
  }))(),
  async execute({ pageId, title, content, versionMessage }) {
    // v2 PUT /pages/{id} is a full replace — both title and body must be sent on every
    // update. Resolve missing fields from the current page so partial updates work.
    // The schema describes empty values as "keep current", so treat empty/whitespace
    // strings as unset (??-fallback would otherwise let "" overwrite a real title).
    const currentPage = await getPage(pageId);
    const storageContent = toStorageContent(content);
    const currentBody = currentPage.body?.storage?.value ?? "";

    const updatedPage = await updatePage(pageId, {
      title: nonEmpty(title) ?? currentPage.title,
      content: storageContent ?? currentBody,
      version: currentPage.version.number + 1,
      versionMessage,
    });

    return {
      id: updatedPage.id,
      title: updatedPage.title,
      type: updatedPage.type ?? "page",
      url: updatedPage._links.webui,
      version: updatedPage.version.number,
      versionMessage: updatedPage.version.message,
    };
  },
});

import { createOAuthCallbackHandler, docsGoogleConfig } from "veryfront/oauth";
import { tokenStore } from "../../../../../lib/token-store.ts";
import { oauthMemoryTokenStore } from "../../../../../lib/oauth-memory-store.ts";

const hybridTokenStore = {
  getTokens(serviceId: string, userId: string) {
    return tokenStore.getToken(userId, serviceId);
  },
  async setTokens(
    serviceId: string,
    userId: string,
    tokens: { accessToken: string; refreshToken?: string; expiresAt?: number },
  ) {
    await tokenStore.setToken(userId, serviceId, tokens);
  },
  async clearTokens(serviceId: string, userId: string) {
    await tokenStore.revokeToken(userId, serviceId);
  },
  setState(
    state: string,
    meta: {
      userId: string;
      serviceId: string;
      codeVerifier?: string;
      redirectUri?: string;
      scopes?: string[];
      createdAt: number;
    },
  ) {
    return oauthMemoryTokenStore.setState(state, meta);
  },
  consumeState(state: string) {
    return oauthMemoryTokenStore.consumeState(state);
  },
};

export const GET = createOAuthCallbackHandler(docsGoogleConfig, { tokenStore: hybridTokenStore });

