    await tokenStore.revokeToken(userId, serviceId);
  },
  setState(
    state: string,
    meta: {
      userId: string;
      serviceId: string;
      codeVerifier?: string;
      redirectUri?: string;
      scopes?: string[];
      createdAt: number;
    },
  ) {
