export async function createIssue(options: {
  teamId: string;
  title: string;
  description?: string;
  priority?: number;
  stateId?: string;
  assigneeId?: string;
  projectId?: string;
  labelIds?: string[];
}): Promise<LinearIssue> {
  const mutation = `
    mutation CreateIssue($input: IssueCreateInput!) {
      issueCreate(input: $input) {
        success
        issue {
          id
          identifier
          title
          description
          priority
          priorityLabel
          state {
            id
            name
            type
          }
          assignee {
            id
            name
            email
          }
          team {
            id
            name
            key
          }
          project {
            id
            name
          }
          labels {
            nodes {
              id
              name
              color
            }
          }
          createdAt
          updatedAt
          url
        }
      }
    }
  `;

  const input: Record<string, unknown> = {
    teamId: options.teamId,
    title: options.title,
  };

  if (options.description) input.description = options.description;
  if (options.priority !== undefined) input.priority = options.priority;
  if (options.stateId) input.stateId = options.stateId;
  if (options.assigneeId) input.assigneeId = options.assigneeId;
  if (options.projectId) input.projectId = options.projectId;
  if (options.labelIds?.length) input.labelIds = options.labelIds;

  const data = await linearFetch<{ issueCreate: { success: boolean; issue: LinearIssue } }>(mutation, {
    input,
  });

  if (!data.issueCreate.success) {
    throw new Error("Failed to create issue");
  }

  return data.issueCreate.issue;
}

export async function updateIssue(
  issueId: string,
  options: {
    title?: string;
    description?: string;
    priority?: number;
